const axios = require('axios');

const input = $input.first().json;
const body = input.body || input;
let content = body.content || '';
const googleDocUrl = body.googleDocUrl || '';
const pdfBase64 = body.pdfBase64 || '';
const pdfFileName = body.pdfFileName || 'document.pdf';
const courseTitle = body.courseTitle || 'Untitled Course';
const courseDescription = body.courseDescription || '';

const ANTHROPIC_KEY = process.env.ANTHROPIC_API_KEY || 'YOUR_KEY';
const SUPABASE_URL = 'https://lxgethcibldfcnmajutf.supabase.co';
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_ROLE_KEY || 'YOUR_KEY';

const systemPrompt = 'You are an expert course designer for a premium LMS platform. Your job is to transform raw content into beautifully structured, pedagogically sound course material.\n\nYou MUST return ONLY valid JSON — no markdown fences, no explanation, no text outside the JSON.\n\nJSON structure:\n{\n  "title": "course title",\n  "description": "2-3 sentence course description",\n  "modules": [\n    {\n      "title": "Module Title",\n      "description": "Brief module description",\n      "sections": [\n        {\n          "title": "Section Title",\n          "blocks": [\n            { "type": "block_type", "content": { ... } }\n          ]\n        }\n      ]\n    }\n  ]\n}\n\nAvailable block types:\n\n1. rich_text — For prose, explanations, instructions\n   { "html": "<p>Content</p>" }\n   Use <h2> for section headings, <h3> for sub-headings, <p> for paragraphs, <ul>/<li> for bullets, <ol>/<li> for numbered lists. Keep paragraphs focused — break long text into multiple rich_text blocks.\n\n2. callout — For highlighted information boxes\n   { "calloutType": "tip|warning|formula|key-insight", "title": "Title", "body": "<p>HTML body</p>" }\n   tip: helpful advice. warning: critical warnings. formula: rules/frameworks. key-insight: key takeaways.\n\n3. table — For structured/tabular data\n   { "rows": [["Header1","Header2"],["Cell1","Cell2"]] } First row is header.\n\n4. workbook_prompt — For exercises, reflection questions\n   { "label": "Question", "placeholder": "Guide text..." } Use generously for engagement.\n\n5. checklist — For action items\n   { "title": "Title", "description": "Optional", "items": ["Item 1"] }\n\n6. video — { "url": "https://..." }\n\n7. file — { "label": "Desc", "fileUrl": "", "fileName": "" }\n\nRules:\n- NEVER summarize or skip content. Include EVERYTHING.\n- Use callouts liberally for key insights, tips, warnings, formulas.\n- Add workbook_prompt blocks for exercises and reflection.\n- Break long text into digestible rich_text blocks.\n- Use tables for tabular data.\n- Each distinct topic = its own section.\n- Sections should have 3-10 blocks for good pacing.\n- Make it feel like a premium, professionally designed course.\n- Ensure the JSON is complete and valid.';

try {
  let claudeMessages;

  if (googleDocUrl.trim()) {
    const docIdMatch = googleDocUrl.match(/\/d\/([a-zA-Z0-9_-]+)/);
    if (!docIdMatch) {
      return [{ json: { success: false, error: 'Invalid Google Doc URL.' } }];
    }
    const exportUrl = 'https://docs.google.com/document/d/' + docIdMatch[1] + '/export?format=txt';
    const docRes = await axios.get(exportUrl, { maxRedirects: 5, responseType: 'text' });
    content = docRes.data;
    if (!content || !content.trim()) {
      return [{ json: { success: false, error: 'Google Doc is empty. Make sure it is shared with Anyone with the link.' } }];
    }
    claudeMessages = [{ role: 'user', content: 'Parse this course content into structured LMS JSON.\nCourse title: "' + courseTitle + '"\n' + (courseDescription ? 'Description: ' + courseDescription + '\n' : '') + '\nContent:\n\n' + content }];

  } else if (pdfBase64.trim()) {
    claudeMessages = [{ role: 'user', content: [{ type: 'document', source: { type: 'base64', media_type: 'application/pdf', data: pdfBase64 } }, { type: 'text', text: 'Parse this PDF into structured LMS course JSON.\nCourse title: "' + courseTitle + '"\n' + (courseDescription ? 'Description: ' + courseDescription : '') + '\nExtract ALL content. Do not skip or summarize anything.' }] }];

  } else if (content.trim()) {
    claudeMessages = [{ role: 'user', content: 'Parse this course content into structured LMS JSON.\nCourse title: "' + courseTitle + '"\n' + (courseDescription ? 'Description: ' + courseDescription + '\n' : '') + '\nContent:\n\n' + content }];

  } else {
    return [{ json: { success: false, error: 'No content provided.' } }];
  }

  const claudeRes = await axios.post('https://api.anthropic.com/v1/messages', {
    model: 'claude-opus-4-20250514',
    max_tokens: 32000,
    system: systemPrompt,
    messages: claudeMessages,
  }, {
    headers: {
      'x-api-key': ANTHROPIC_KEY,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json',
    },
    timeout: 300000,
  });

  const claudeData = claudeRes.data;
  if (claudeData.error) {
    return [{ json: { success: false, error: 'Claude API error: ' + claudeData.error.message } }];
  }

  let responseText = claudeData.content[0].text;
  responseText = responseText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

  let parsed;
  try {
    parsed = JSON.parse(responseText);
  } catch (e) {
    const jsonMatch = responseText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try { parsed = JSON.parse(jsonMatch[0]); } catch (e2) {
        return [{ json: { success: false, error: 'Failed to parse JSON', raw: responseText.substring(0, 500) } }];
      }
    } else {
      return [{ json: { success: false, error: 'No JSON in response', raw: responseText.substring(0, 500) } }];
    }
  }

  async function dbInsert(table, data) {
    const res = await axios.post(SUPABASE_URL + '/rest/v1/' + table, data, {
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': 'Bearer ' + SUPABASE_KEY,
        'Content-Type': 'application/json',
        'Prefer': 'return=representation',
      },
    });
    return Array.isArray(res.data) ? res.data[0] : res.data;
  }

  const course = await dbInsert('courses', {
    title: parsed.title || courseTitle,
    description: parsed.description || courseDescription || null,
    status: 'draft',
    sort_order: 0,
  });

  if (!course || !course.id) {
    return [{ json: { success: false, error: 'Failed to create course', detail: JSON.stringify(course) } }];
  }

  let totalModules = 0, totalSections = 0, totalBlocks = 0;

  for (let mi = 0; mi < (parsed.modules || []).length; mi++) {
    const mod = parsed.modules[mi];
    const module = await dbInsert('modules', {
      course_id: course.id,
      title: mod.title,
      description: mod.description || null,
      sort_order: mi,
    });
    totalModules++;
    if (!module || !module.id) continue;

    for (let si = 0; si < (mod.sections || []).length; si++) {
      const sec = mod.sections[si];
      const section = await dbInsert('sections', {
        module_id: module.id,
        title: sec.title,
        sort_order: si,
      });
      totalSections++;
      if (!section || !section.id) continue;

      const blocks = (sec.blocks || []).map((b, bi) => ({
        section_id: section.id,
        type: b.type,
        content: b.content,
        sort_order: bi,
      }));

      if (blocks.length > 0) {
        const batchRes = await axios.post(SUPABASE_URL + '/rest/v1/content_blocks', blocks, {
          headers: {
            'apikey': SUPABASE_KEY,
            'Authorization': 'Bearer ' + SUPABASE_KEY,
            'Content-Type': 'application/json',
            'Prefer': 'return=representation',
          },
        });
        totalBlocks += Array.isArray(batchRes.data) ? batchRes.data.length : 1;
      }
    }
  }

  return [{
    json: {
      success: true,
      courseId: course.id,
      courseTitle: course.title,
      modulesCreated: totalModules,
      sectionsCreated: totalSections,
      blocksCreated: totalBlocks,
      message: 'Course "' + course.title + '" imported with ' + totalModules + ' modules, ' + totalSections + ' sections, and ' + totalBlocks + ' content blocks.',
    }
  }];
} catch (err) {
  const msg = err.response ? JSON.stringify(err.response.data).substring(0, 500) : (err.message || 'Unknown error');
  return [{ json: { success: false, error: msg } }];
}
